      </div>

      {/* Custom template indicator */}
      {(customTpl.customIntro || customTpl.headerTheme !== "blue") && (
        <div className="custom-tpl-badge">
          🎨 Custom template active —
          <span style={{ color: HEADER_THEMES.find(h => h.id === customTpl.headerTheme)?.color }}>
